  ('medical-tech-moex-14758', 'medical-tech', 'medical-tech-moex-099-716b3930', 'sub-medical-tech-07', NULL, 'single_choice', '由細菌所引起的足菌腫（bacterial mycetoma），其傷口檢體可看到菌絲體狀的硫磺顆粒是屬於下列何菌 屬？', '["Nocardia spp", "Actinomadura spp", "Streptomyces spp", "Acremonium spp"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:00+00:00", "source_pdf_sha1": "3fcb249baa6d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-14759', 'medical-tech', 'medical-tech-moex-099-716b3930', 'sub-medical-tech-07', NULL, 'single_choice', '下列接合菌綱（Zygomycetes）中，何者具假根（rhizoids）構造，但並不直接連接在孢子囊柄 （sporangiophore）基底（bases）下生長？', '["Absidia spp", "Mucor spp", "Rhizopus spp", "Circinella spp"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:00+00:00", "source_pdf_sha1": "3fcb249baa6d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-14760', 'medical-tech', 'medical-tech-moex-099-716b3930', 'sub-medical-tech-07', NULL, 'single_choice', '下列何種黴菌在鏡檢下之型態是有單一到多個細胞數的大分生孢子（macroconidia），且成鐮刀狀 （sickle-shaped）？', '["Acremonium spp", "Aspergillus spp", "Fusarium spp", "Geotrichum spp"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:00+00:00", "source_pdf_sha1": "3fcb249baa6d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
